import{_ as a,p as e,q as s,a1 as n}from"./framework-5866ffd3.js";const l={},r=n(`<h1 id="logwatch" tabindex="-1"><a class="header-anchor" href="#logwatch" aria-hidden="true">#</a> logwatch</h1><p>可定制和可插入式的日志监视系统</p><h2 id="补充说明" tabindex="-1"><a class="header-anchor" href="#补充说明" aria-hidden="true">#</a> 补充说明</h2><p><strong>logwatch命令</strong> 是一个可定制和可插入式的日志监视系统，它通过遍历给定时间范围内的系统日志文件而产生日志报告。logwatch默认每天执行一次，可以从<code>/etc/cron.daily</code>里看到。</p><h3 id="语法" tabindex="-1"><a class="header-anchor" href="#语法" aria-hidden="true">#</a> 语法</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>logwatch<span class="token punctuation">(</span>选项<span class="token punctuation">)</span>
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><h3 id="选项" tabindex="-1"><a class="header-anchor" href="#选项" aria-hidden="true">#</a> 选项</h3><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>--detail<span class="token operator">&lt;</span>报告详细程度<span class="token operator">&gt;</span>：指定日志报告的详细程度；
--logfile<span class="token operator">&lt;</span>日志文件<span class="token operator">&gt;</span>：仅处理指定的日志文件；
--service<span class="token operator">&lt;</span>服务名<span class="token operator">&gt;</span>：仅处理指定服务的日志文件；
--print：打印结果到标准输出；
--mailto<span class="token operator">&lt;</span>邮件地址<span class="token operator">&gt;</span>：将结果发送到指定邮箱；
--range<span class="token operator">&lt;</span>日期范围<span class="token operator">&gt;</span>：指定处理日志的日期范围；
--archives：处理归档日志文件；
--debug<span class="token operator">&lt;</span>调试等级<span class="token operator">&gt;</span>：调试模式；
--save<span class="token operator">&lt;</span>文件名<span class="token operator">&gt;</span>：将结果保存到指定文件中，而不显示或者发送到指定邮箱；
--logdir<span class="token operator">&lt;</span>目录<span class="token operator">&gt;</span>：指定查找日志文件的目录，而不使用默认的日志目录；
--hostname<span class="token operator">&lt;</span>主机名<span class="token operator">&gt;</span>：指定在日志报告中使用的主机名，不使用系统默认的主机名；
--numeric：在报告中显示ip地址而不是主机名；
--help：显示指令的帮助信息。
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div><div class="line-number"></div></div></div><h3 id="实例" tabindex="-1"><a class="header-anchor" href="#实例" aria-hidden="true">#</a> 实例</h3><p>检查你的主机上是否已经存在Logwatch（Redhat默认已经安装了Logwatch，不过版本比较旧）：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rpm</span> <span class="token parameter variable">-qa</span> logwatch
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果主机上没有logwatch，则执行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rpm</span> <span class="token parameter variable">-Ivh</span> logwatch***.rpm
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>如果有老版本的logwatch，则执行：</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code><span class="token function">rpm</span> <span class="token parameter variable">-Uvh</span> logwatch***.rpm
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div></div></div><p>安装完毕后，开始配置：</p><p>可以修改和添加它的logfiles、services和其他配置，但默认已经有很多脚本了，只要在1）里设置<code>Detail = High</code>就可以了。</p><ul><li>可以添加新的配置到<code>/etc/logwatch/conf/logwatch.conf</code></li><li>也可以修改<code>/usr/share/logwatch/default.conf/logwatch.conf</code></li></ul><p><code>/etc/logwatch/conf/</code>会自动覆盖<code>/usr/share/logwatch/default.conf/</code>下的同名文件。</p><p>如果没有设置logwatch.conf也没关系，可以直接在命令行下设置。</p><div class="language-bash line-numbers-mode" data-ext="sh"><pre class="language-bash"><code>logwatch <span class="token parameter variable">--detail</span> High <span class="token parameter variable">--Service</span> All <span class="token parameter variable">--range</span> All <span class="token parameter variable">--print</span>    基本就可以显示出所有日志的情况了
logwatch <span class="token parameter variable">--service</span> sshd <span class="token parameter variable">--detail</span> High                       只看sshd的日志情况
</code></pre><div class="line-numbers" aria-hidden="true"><div class="line-number"></div><div class="line-number"></div></div></div>`,21),i=[r];function t(c,o){return e(),s("div",null,i)}const p=a(l,[["render",t],["__file","logwatch.html.vue"]]);export{p as default};
